    addQuickNote: function() {
        const input = document.getElementById('new-note-input');
        const colorSelect = document.getElementById('note-color');
        const text = input?.value?.trim();

        if (!text) {
            toast.warning('Please enter a note');
            return;
        }

        const notes = store.state.quickNotes || [];
        notes.unshift({
            text,
            color: colorSelect?.value || 'default',
            createdAt: new Date().toISOString()
        });

        store.setState({ quickNotes: notes });
        toast.success('Note added');
        handlers._showQuickNotesImpl(); // Refresh
    },


    deleteQuickNote: function(index) {
        const notes = store.state.quickNotes || [];
        notes.splice(index, 1);
        store.setState({ quickNotes: notes });
        toast.success('Note deleted');
        handlers._showQuickNotesImpl(); // Refresh
    },


    convertNoteToTask: function(index) {
        const notes = store.state.quickNotes || [];
        const note = notes[index];
        if (note) {
            const tasks = store.state.checklistTasks || [];
            tasks.push({
                id: Date.now(),
                title: note.text,
                completed: false,
                priority: 'medium',
                createdAt: new Date().toISOString()
            });
            store.setState({ checklistTasks: tasks });

            // Remove from notes
            notes.splice(index, 1);
            store.setState({ quickNotes: notes });

            toast.success('Converted to task');
            handlers._showQuickNotesImpl(); // Refresh
        }
    },


    selectAllChecklistItems: async function() {
        const items = store.state.checklistItems || [];
        if (items.length === 0) {
            toast.info('No tasks to select');
            return;
        }
        const allChecked = items.every(i => i.completed);
        const newStatus = !allChecked;
        let failCount = 0;

        await api.ensureCSRFToken();
        for (const item of items) {
            if (item.completed !== newStatus) {
                try {
                    await api.patch(`/checklists/items/${item.id}`, { completed: newStatus });
                } catch(e) {
                    console.error('Failed to update item:', e);
                    failCount++;
                }
            }
        }

        store.setState({ checklistItems: items.map(i => ({ ...i, completed: newStatus })) });
        if (failCount === 0) {
            toast.success(newStatus ? 'All items completed' : 'All items unchecked');
        } else {
            toast.warning(`Updated most items but ${failCount} failed to save`);
        }

        if (store.state.currentPage === 'checklist') {
            renderApp(window.pages.checklist());
        }
    },


