    // Calculate receipt totals from line items,


    calculateReceiptTotals: function() {
        const rows = document.querySelectorAll('.receipt-line-item-row');
        let subtotal = 0;

        rows.forEach(row => {
            const qty = parseFloat(row.querySelector('[name="itemQty"]')?.value) || 1;
            const unitPrice = parseFloat(row.querySelector('[name="itemUnitPrice"]')?.value) || 0;
            const total = qty * unitPrice;

            const totalInput = row.querySelector('[name="itemTotal"]');
            if (totalInput) totalInput.value = total.toFixed(2);
            subtotal += total;
        });

        const subtotalInput = document.getElementById('receipt-subtotal');
        const totalInput = document.getElementById('receipt-total');

        if (subtotalInput) subtotalInput.value = subtotal.toFixed(2);

        const discount = parseFloat(document.getElementById('receipt-discount')?.value) || 0;
        const shipping = parseFloat(document.getElementById('receipt-shipping')?.value) || 0;

        if (totalInput) {
            totalInput.value = (subtotal + shipping - discount).toFixed(2);
        }
    },

