    // Subscribe to push notifications,


    showChecklistAnalytics: function() {
        const items = store.state.checklistItems || [];
        const total = items.length;
        const completed = items.filter(i => i.completed || i.status === 'completed').length;
        const completionRate = total > 0 ? Math.round((completed / total) * 100) : 0;

        // Completion by priority
        const priorities = { high: { total: 0, done: 0 }, medium: { total: 0, done: 0 }, low: { total: 0, done: 0 } };
        items.forEach(i => {
            const p = (i.priority || 'medium').toLowerCase();
            if (priorities[p]) {
                priorities[p].total++;
                if (i.completed || i.status === 'completed') priorities[p].done++;
            }
        });

        // Completion by category
        const categories = {};
        items.forEach(i => {
            const cat = i.category || 'Uncategorized';
            if (!categories[cat]) categories[cat] = { total: 0, done: 0 };
            categories[cat].total++;
            if (i.completed || i.status === 'completed') categories[cat].done++;
        });

        // Weekly completion trend (last 7 days)
        const weekData = [];
        const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
        for (let d = 6; d >= 0; d--) {
            const date = new Date();
            date.setDate(date.getDate() - d);
            const dateStr = toLocalDate(date);
            const dayCompleted = items.filter(i => {
                const completedAt = i.completed_at || i.updated_at;
                return (i.completed || i.status === 'completed') && completedAt && completedAt.startsWith(dateStr);
            }).length;
            weekData.push({ day: dayNames[date.getDay()], count: dayCompleted, date: dateStr });
        }
        const maxWeek = Math.max(...weekData.map(d => d.count), 1);
        const avgPerDay = total > 0 ? (completed / 7).toFixed(1) : '0';

        modals.show(`
            <div class="modal-header">
                <h2 class="modal-title">${components.icon('bar-chart-2', 20)} Checklist Analytics</h2>
                <button class="modal-close" aria-label="Close" onclick="modals.close()">${components.icon('close')}</button>
            </div>
            <div class="modal-body checklist-analytics-container">
                <div class="analytics-summary-row">
                    <div class="analytics-stat">
                        <div class="analytics-stat-value">${total}</div>
                        <div class="analytics-stat-label">Total Tasks</div>
                    </div>
                    <div class="analytics-stat">
                        <div class="analytics-stat-value">${completed}</div>
                        <div class="analytics-stat-label">Completed</div>
                    </div>
                    <div class="analytics-stat">
                        <div class="analytics-stat-value">${completionRate}%</div>
                        <div class="analytics-stat-label">Completion Rate</div>
                    </div>
                    <div class="analytics-stat">
                        <div class="analytics-stat-value">${avgPerDay}</div>
                        <div class="analytics-stat-label">Avg Tasks/Day</div>
                    </div>
                </div>

                <div class="priority-breakdown">
                    <h3>Completion by Priority</h3>
                    ${['high', 'medium', 'low'].map(p => {
                        const data = priorities[p];
                        const pct = data.total > 0 ? Math.round((data.done / data.total) * 100) : 0;
                        const colorClass = p === 'high' ? 'error' : p === 'medium' ? 'warning' : 'success';
                        return '<div class="priority-row">' +
                            '<div class="priority-label">' +
                                '<span class="priority-name">' + p.charAt(0).toUpperCase() + p.slice(1) + '</span>' +
                                '<span class="priority-count">' + data.done + '/' + data.total + '</span>' +
                            '</div>' +
                            '<div class="priority-bar-track">' +
                                '<div class="priority-bar priority-bar-' + colorClass + '" style="width: ' + pct + '%"></div>' +
                            '</div>' +
                            '<span class="priority-pct">' + pct + '%</span>' +
                        '</div>';
                    }).join('')}
                </div>

                ${Object.keys(categories).length > 1 ? `
                <div class="category-breakdown">
                    <h3>Completion by Category</h3>
                    ${Object.entries(categories).map(([cat, data]) => {
                        const pct = data.total > 0 ? Math.round((data.done / data.total) * 100) : 0;
                        return '<div class="priority-row">' +
                            '<div class="priority-label">' +
                                '<span class="priority-name">' + escapeHtml(cat) + '</span>' +
                                '<span class="priority-count">' + data.done + '/' + data.total + '</span>' +
                            '</div>' +
                            '<div class="priority-bar-track">' +
                                '<div class="priority-bar priority-bar-primary" style="width: ' + pct + '%"></div>' +
                            '</div>' +
                            '<span class="priority-pct">' + pct + '%</span>' +
                        '</div>';
                    }).join('')}
                </div>
                ` : ''}

                <div class="weekly-trend">
                    <h3>Weekly Completion Trend</h3>
                    <div class="trend-chart">
                        ${weekData.map(d => `
                            <div class="trend-bar-group">
                                <div class="trend-bar-container">
                                    <div class="trend-bar" style="height: ${d.count > 0 ? Math.max((d.count / maxWeek) * 100, 8) : 4}%"></div>
                                </div>
                                <span class="trend-bar-count">${d.count}</span>
                                <span class="trend-bar-label">${d.day}</span>
                            </div>
                        `).join('')}
                    </div>
                </div>

                <div class="productivity-tips">
                    <h3>${components.icon('zap', 16)} Productivity Tips</h3>
                    <ul>
                        ${completionRate < 50 ? '<li>Try breaking large tasks into smaller sub-tasks to build momentum</li>' : ''}
                        ${completionRate >= 50 && completionRate < 80 ? '<li>Great progress! Focus on high-priority items first to maximize impact</li>' : ''}
                        ${completionRate >= 80 ? '<li>Excellent completion rate! Consider adding stretch goals to stay productive</li>' : ''}
                        ${priorities.high.total > 0 && priorities.high.done < priorities.high.total ? '<li>You have ' + (priorities.high.total - priorities.high.done) + ' high-priority task' + ((priorities.high.total - priorities.high.done) !== 1 ? 's' : '') + ' remaining - tackle these first</li>' : ''}
                        <li>Use templates to quickly set up recurring daily tasks</li>
                    </ul>
                </div>
            </div>
            <div class="modal-footer">
                <button class="btn btn-secondary" onclick="modals.close()">Close</button>
            </div>
        `, 'modal-lg');
    },

