    submitShareChecklist: async function() {
        const email = document.getElementById('share-checklist-email')?.value?.trim();
        const permission = document.getElementById('share-checklist-permission')?.value || 'view';
        const teamMembers = Array.from(document.querySelectorAll('.share-team-member:checked')).map(cb => cb.value);

        const recipients = [...(email ? [email] : []), ...teamMembers];
        if (recipients.length === 0) {
            showToast('Please enter an email or select a team member', 'error');
            return;
        }

        try {
            for (const recipient of recipients) {
                await api.post('/checklists/share', { shared_with: recipient, permission });
            }
            showToast(`Checklist shared with ${recipients.length} recipient${recipients.length > 1 ? 's' : ''}`, 'success');
            modals.close();
        } catch (err) {
            showToast('Failed to share checklist: ' + (err.message || 'Unknown error'), 'error');
        }
    },

    // showCustomMetricBuilder: moved to handlers-core.js (Fix A)


    saveCustomMetric: async function() {
        const name = document.getElementById('custom-metric-name')?.value?.trim();
        const metric_a = document.getElementById('custom-metric-a')?.value;
        const operation = document.getElementById('custom-metric-op')?.value;
        const metric_b = document.getElementById('custom-metric-b')?.value;
        const display_format = document.getElementById('custom-metric-format')?.value;

        if (!name) {
            showToast('Please enter a metric name', 'error');
            return;
        }

        try {
            const res = await api.post('/analytics/custom-metrics', { name, metric_a, operation, metric_b, display_format });
            const metrics = store.state.customMetrics || [];
            metrics.push(res.metric || { id: Date.now().toString(), name, metric_a, operation, metric_b, display_format });
            store.setState({ customMetrics: metrics });
            showToast('Custom KPI created: ' + name, 'success');
            modals.close();
            renderApp(window.pages.analytics());
        } catch (err) {
            showToast('Failed to create metric: ' + (err.message || 'Unknown error'), 'error');
        }
    },


    deleteCustomMetric: async function(metricId) {
        try {
            await api.delete('/analytics/custom-metrics/' + metricId);
            const metrics = (store.state.customMetrics || []).filter(m => m.id !== metricId);
            store.setState({ customMetrics: metrics });
            showToast('Custom KPI removed', 'success');
            renderApp(window.pages.analytics());
        } catch (err) {
            showToast('Failed to remove metric: ' + (err.message || 'Unknown error'), 'error');
        }
    },

