    // Account Usage Statistics,


    addChecklistAttachment: function(mode) {
        const inputId = mode === 'add' ? 'add-attachment-input' : 'edit-attachment-input';
        const input = document.getElementById(inputId);
        if (!input || !input.value.trim()) { toast.warning('Enter a file name or URL'); return; }
        const name = input.value.trim();
        if (mode === 'add') {
            handlers._addChecklistAttachments.push(name);
        } else {
            handlers._editChecklistAttachments.push(name);
        }
        input.value = '';
        const listId = mode === 'add' ? 'add-attachments-list' : 'edit-attachments-list';
        const listEl = document.getElementById(listId);
        if (listEl) {
            const arr = mode === 'add' ? handlers._addChecklistAttachments : handlers._editChecklistAttachments;
            // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
            listEl.innerHTML = sanitizeHTML(arr.map((a, i) => `
                <span class="checklist-attachment-tag">
                    ${components.icon('paperclip', 12)} ${escapeHtml(a)}
                    <button type="button" class="btn btn-ghost btn-xs" onclick="handlers.removeChecklistAttachment('${mode}', ${i})" aria-label="Remove attachment">${components.icon('x', 10)}</button>
                </span>
            `).join(''));
        }
    },


    removeChecklistAttachment: function(mode, index) {
        if (mode === 'add') {
            handlers._addChecklistAttachments.splice(index, 1);
        } else {
            handlers._editChecklistAttachments.splice(index, 1);
        }
        const listId = mode === 'add' ? 'add-attachments-list' : 'edit-attachments-list';
        const listEl = document.getElementById(listId);
        if (listEl) {
            const arr = mode === 'add' ? handlers._addChecklistAttachments : handlers._editChecklistAttachments;
            // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
            listEl.innerHTML = sanitizeHTML(arr.map((a, i) => `
                <span class="checklist-attachment-tag">
                    ${components.icon('paperclip', 12)} ${escapeHtml(a)}
                    <button type="button" class="btn btn-ghost btn-xs" onclick="handlers.removeChecklistAttachment('${mode}', ${i})" aria-label="Remove attachment">${components.icon('x', 10)}</button>
                </span>
            `).join(''));
        }
    },

